// wikipedia.service.ts
import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, catchError, map, of } from 'rxjs';

export interface WikipediaSearchResult {
  pageid: number;
  title: string;
  snippet: string;
}

export interface WikipediaPageData {
  title: string;
  extract: string;        // HTML dell'estratto
  thumbnail?: { source: string; width: number; height: number };
  content_urls?: { desktop: { page: string } };
}

@Injectable({ providedIn: 'root' })
export class WikipediaService {
  private http = inject(HttpClient);

  private actionApi = 'https://it.wikipedia.org/w/api.php';

  /**
   * Cerca pagine il cui titolo contiene il termine.
   * Restituisce un array di risultati con pageid, title, snippet.
   */
  search(term: string): Observable<WikipediaSearchResult[]> {
    if (!term.trim()) return of([]);

    const params = {
      action: 'query',
      list: 'search',
      srsearch: term,
      format: 'json',
      origin: '*',
      srlimit: 10,
    };

    return this.http.get(this.actionApi, { params }).pipe(
      map((res: any) => res.query?.search || []),
      catchError(this.handleError('search', []))
    );
  }

  /**
   * Ottiene i dati di una pagina: titolo, estratto (HTML), thumbnail e URL.
   * @param title Titolo esatto della pagina
   * @param full Se true, restituisce un estratto più lungo (non solo introduzione)
   */
getPageData(title: string, full: boolean = false): Observable<WikipediaPageData | null> {
  const params: any = {
    action: 'query',
    titles: title,
    prop: 'extracts|pageimages|info',
    explaintext: false,
    piprop: 'thumbnail',
    pithumbsize: 300,
    inprop: 'url',
    format: 'json',
    origin: '*'
  };

  if (full) {
    params.exchars = 5000;      // 5000 caratteri massimi
  } else {
    params.exintro = true;      // solo introduzione
  }

  return this.http.get(this.actionApi, { params }).pipe(
    map((res: any) => {
      const pages = res.query?.pages;
      const pageId = Object.keys(pages)[0];
      const page = pages[pageId];
      if (!page) return null;
      
      let extract = page.extract || '';
      // Conversione di emergenza (se explaintext=false funziona, non serve)
      if (extract.includes('==') || extract.includes("'''")) {
        extract = this.wikitextToHtml(extract);
      }

      return {
        title: page.title,
        extract: extract,
        thumbnail: page.thumbnail,
        content_urls: {
          desktop: { page: page.fullurl }
        }
      };
    }),
    catchError(this.handleError('getPageData', null))
  );
}

  private handleError(method: string, fallback: any) {
    return (error: any): Observable<any> => {
      console.error(`WikipediaService.${method} error:`, error);
      return of(fallback);
    };
  }

  private wikitextToHtml(text: string): string {
  if (!text) return '';

  // Proteggi blocchi di codice e pre (da migliorare se necessario)
  // Converti titoli
  let html = text
    // Titoli di livello 2 (== ... ==)
    .replace(/^==\s*(.+?)\s*==$/gm, '<h2>$1</h2>')
    // Titoli di livello 3 (=== ... ===)
    .replace(/^===\s*(.+?)\s*===$/gm, '<h3>$1</h3>')
    // Titoli di livello 4 (==== ... ====)
    .replace(/^====\s*(.+?)\s*====$/gm, '<h4>$1</h4>')
    // Liste non ordinate (linee che iniziano con * seguiti da spazio)
    .replace(/^\*\s+(.+)$/gm, '<li>$1</li>')
    // Liste ordinate (linee che iniziano con #)
    .replace(/^#\s+(.+)$/gm, '<li style="list-style-type: decimal;">$1</li>')
    // Grassetto ('''...''')
    .replace(/'''(.*?)'''/g, '<strong>$1</strong>')
    // Corsivo (''...'')
    .replace(/''(.*?)''/g, '<em>$1</em>')
    // Link interni [[...]] - semplice, senza namespace
    .replace(/\[\[(?:[^|\]]*\|)?([^\]]+)\]\]/g, '<a href="#">$1</a>') // senza URL reale
    // Link esterni [http://example.com testo]
    .replace(/\[(https?:\/\/[^\s]+)\s+([^\]]+)\]/g, '<a href="$1" target="_blank" rel="noopener">$2</a>')
    // Newline in <br> (ma gestiamo meglio i paragrafi)
    ;

  // Raggruppa le linee in paragrafi (doppi newline)
  const paragraphs = html.split(/\n\s*\n/);
  html = paragraphs.map(p => {
    p = p.trim();
    if (p.startsWith('<h') || p.startsWith('<li')) return p; // lascia i tag
    return `<p>${p.replace(/\n/g, '<br>')}</p>`;
  }).join('\n');

  return html;
}


  // FILTRO RICERCHE
getCategoriesForPages(pageids: number[]): Observable<Map<number, string[]>> {
  if (pageids.length === 0) return of(new Map());
  const params = {
    action: 'query',
    pageids: pageids.join('|'),
    prop: 'categories',
    cllimit: 'max',
    format: 'json',
    origin: '*'
  };
  return this.http.get(this.actionApi, { params }).pipe(
    map((res: any) => {
      const map = new Map<number, string[]>();
      const pages = res.query?.pages;
      if (pages) {
        Object.values(pages).forEach((page: any) => {
          const cats = page.categories?.map((c: any) => c.title) || [];
          map.set(page.pageid, cats);
        });
      }
      return map;
    }),
    catchError(this.handleError('getCategoriesForPages', new Map()))
  );
}

}