  searchControl = new FormControl('');
  results: WikipediaSearchResult[] = [];
  selectedPage: any = null;
  loading = false;
  error: string | null = null;
  isFullContent = false;


  ngOnInit() {
    this.searchControl.valueChanges.pipe(
      debounceTime(500),
      distinctUntilChanged(),
      switchMap(term => this.performSearch(term)),
      takeUntilDestroyed(this.destroyRef)
    ).subscribe(results => {
      this.results = results;
      this.loading = false;
    });
  }

private performSearch(term: string | null): Observable<WikipediaSearchResult[]> {
  if (!term) {
    this.results = [];
    return of([]);
  }
  this.loading = true;
  this.error = null;

  return this.wikiService.search(term).pipe(
    switchMap(results => {
      if (results.length === 0) return of([]);
      const pageids = results.map(r => r.pageid);
      return this.wikiService.getCategoriesForPages(pageids).pipe(
        map((categoriesMap: Map<number, string[]>) => {
          // Filtra i risultati che appartengono ad almeno una categoria culinaria
          const filtered = results.filter(result => {
            const cats = categoriesMap.get(result.pageid) || [];
            return cats.some(cat => this.isCulinaryCategory(cat));
          });
          // Se il filtro elimina tutto, restituisci i risultati originali (fallback)
          return filtered.length > 0 ? filtered : results;
        })
      );
    }),
    catchError(err => {
      this.error = 'Errore durante la ricerca';
      return of([]);
    })
  );
}

private isCulinaryCategory(category: string): boolean {
  return this.CULINARY_CATEGORIES.some(keyword => category.startsWith(keyword));
}

  selectResult(result: any) {
    this.loading = true;
    this.error = null;
    this.isFullContent = false;    // reset
    this.wikiService.getPageData(result.title, false).pipe(
      catchError(err => {
        this.error = 'Impossibile caricare la pagina';
        return of(null);
      })
    ).subscribe(data => {
      this.selectedPage = data;
      this.loading = false;
    });
  }


  loadFullContent() {
    if (!this.selectedPage) return;
    this.loading = true;
    this.error = null;
    this.wikiService.getPageData(this.selectedPage.title, true).pipe(
      catchError(err => {
        this.error = 'Impossibile caricare il contenuto esteso';
        return of(null);
      })
    ).subscribe(data => {
      this.selectedPage = data;
      console.log('Estratto ricevuto:', data?.extract);
      this.isFullContent = true;
      this.loading = false;
    });
  }


  clearSearch() {
    this.searchControl.setValue('');
    this.results = [];
    this.selectedPage = null;
    this.isFullContent = false;
  }

  forceSearch() {
    this.performSearch(this.searchControl.value).subscribe(results => {
      this.results = results;
    });
  }


